// InviteWorker is the resolver for the inviteWorker field.
func (r *mutationResolver) InviteWorker(ctx context.Context, input model.InviteWorkerInput) (*model.WorkerProfile, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	// Get the company for this admin user
	company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("you need to register your company before inviting workers")
	}

	// Verify company is approved before allowing worker invitations
	if company.Status != db.CompanyStatusApproved {
		return nil, fmt.Errorf("your company is not yet approved. only approved companies can invite workers")
	}

	// Step 1: Create User record with pending status
	user, err := r.Queries.CreateWorkerUser(ctx, db.CreateWorkerUserParams{
		Email:    input.Email,
		FullName: input.FullName,
		Phone:    stringToText(input.Phone),
		Status:   db.UserStatusPending, // Pending until invitation accepted
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create user for worker: %w", err)
	}

	// Step 2: Generate invite token
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return nil, fmt.Errorf("failed to generate invite token: %w", err)
	}
	inviteToken := "inv-" + hex.EncodeToString(tokenBytes)

	// Step 3: Create Worker profile linked to user
	worker, err := r.Queries.CreateWorkerProfile(ctx, db.CreateWorkerProfileParams{
		UserID:         user.ID,
		CompanyID:      company.ID,
		Status:         db.WorkerStatusInvited,
		IsCompanyAdmin: pgtype.Bool{Bool: false, Valid: true},
		InviteToken:    stringToTextVal(inviteToken),
		InviteExpiresAt: pgtype.Timestamptz{
			Time:  time.Now().Add(7 * 24 * time.Hour),
			Valid: true,
		},
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create worker profile: %w", err)
	}

	// Auto-assign all company service areas to the new worker
	r.copyCompanyAreasToWorkerHelper(ctx, company.ID, worker.ID)

	// Notify the invited worker by email and upsert contact (non-blocking).
	workerInviteToken := textVal(worker.InviteToken)
	go func() {
		inviteToken := workerInviteToken
		acceptURL := buildInviteURL(inviteToken)
		r.NotifSvc.Dispatch(notification.EventWorkerInvited,
			notification.Payload{
				"companyName": company.CompanyName,
				"workerName":  input.FullName,
				"inviteToken": inviteToken,
				"acceptUrl":   acceptURL,
			},
			[]notification.Target{{Email: input.Email, Name: input.FullName}},
		)
		r.NotifSvc.UpsertContact(context.Background(), notification.ContactData{
			Email:    input.Email,
			Name:     input.FullName,
			UserType: "worker",
			Status:   "active",
		})
	}()

	return r.workerWithCompany(ctx, worker)
}

