// AcceptInvitation is the resolver for the acceptInvitation field.
func (r *mutationResolver) AcceptInvitation(ctx context.Context, token string) (*model.WorkerProfile, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	// Look up worker by invite token
	worker, err := r.Queries.GetWorkerByInviteToken(ctx, stringToTextVal(token))
	if err != nil {
		return nil, fmt.Errorf("invalid invitation token: %w", err)
	}

	currentUserID := stringToUUID(claims.UserID)

	// Security check: if the invitation was issued for a specific user (UserID is set),
	// verify that the authenticated caller's email matches the intended recipient's email.
	// This prevents any logged-in user from hijacking an invitation meant for someone else.
	if worker.UserID.Valid {
		invitedUser, err := r.Queries.GetUserByID(ctx, worker.UserID)
		if err != nil {
			return nil, fmt.Errorf("invalid invitation: could not verify intended recipient: %w", err)
		}
		if !strings.EqualFold(invitedUser.Email, claims.Email) {
			return nil, fmt.Errorf("Această invitație a fost trimisă la o altă adresă de email.")
		}
	}

	// Case 1: Invited worker has their own pending user, accepting user is different
	// Transfer the worker association to the current user and delete pending user
	if worker.UserID.Valid && uuidToString(worker.UserID) != claims.UserID {
		pendingUserID := worker.UserID

		// Link worker to current user
		worker, err = r.Queries.LinkWorkerToUser(ctx, db.LinkWorkerToUserParams{
			ID:     worker.ID,
			UserID: currentUserID,
		})
		if err != nil {
			return nil, fmt.Errorf("failed to link worker to user: %w", err)
		}

		// Delete the pending user (no longer needed)
		if err := r.Queries.DeleteUser(ctx, pendingUserID); err != nil {
			// Non-fatal - log but continue
			fmt.Printf("Warning: failed to delete pending user %s: %v\n", uuidToString(pendingUserID), err)
		}
	}

	// Set worker status to pending_review (requires personality test, documents, and admin approval)
	worker, err = r.Queries.UpdateWorkerStatus(ctx, db.UpdateWorkerStatusParams{
		ID:     worker.ID,
		Status: db.WorkerStatusPendingReview,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to update worker status: %w", err)
	}

	// Upgrade user role
	_, err = r.Queries.UpdateUserRole(ctx, db.UpdateUserRoleParams{
		ID:   currentUserID,
		Role: db.UserRoleWorker,
	})
	if err != nil {
		fmt.Printf("Warning: failed to upgrade user role: %v\n", err)
	}

	// Activate user status
	_, err = r.Queries.UpdateUserStatus(ctx, db.UpdateUserStatusParams{
		ID:     currentUserID,
		Status: db.UserStatusActive,
	})
	if err != nil {
		fmt.Printf("Warning: failed to activate user: %v\n", err)
	}

	// Notify company admin that the worker accepted the invitation.
	go func(w db.Worker) {
		bgCtx := context.Background()
		company, cErr := r.Queries.GetCompanyByID(bgCtx, w.CompanyID)
		if cErr != nil || !company.AdminUserID.Valid {
			return
		}
		if _, nErr := r.Queries.CreateNotification(bgCtx, db.CreateNotificationParams{
			UserID: company.AdminUserID,
			Type:   db.NotificationTypeWorkerAccepted,
			Title:  "Lucrător a acceptat invitația",
			Body:   "Un lucrător a acceptat invitația și și-a creat profilul. Verificați profilul pentru aprobare.",
			Data:   []byte(fmt.Sprintf(`{"workerId":"%s"}`, uuidToString(w.ID))),
		}); nErr != nil {
			log.Printf("acceptInvitation: failed to notify company admin: %v", nErr)
		}
	}(worker)

	return r.workerWithCompany(ctx, worker)
}

// UpdateAvailability is the resolver for the updateAvailability field.
func (r *mutationResolver) UpdateAvailability(ctx context.Context, slots []*model.AvailabilitySlotInput) ([]*model.AvailabilitySlot, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	worker, err := r.Queries.GetWorkerByUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("worker profile not found: %w", err)
	}

	// Delete existing availability and recreate.
	err = r.Queries.DeleteWorkerAvailability(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to clear availability: %w", err)
	}

	var result []*model.AvailabilitySlot
	for _, slot := range slots {
		// Parse start time.
		startTime, _ := time.Parse("15:04", slot.StartTime)
		endTime, _ := time.Parse("15:04", slot.EndTime)

		avail, err := r.Queries.SetWorkerAvailability(ctx, db.SetWorkerAvailabilityParams{
			WorkerID:  worker.ID,
			DayOfWeek: int32(slot.DayOfWeek),
			StartTime: pgtype.Time{
				Microseconds: int64(startTime.Hour())*3_600_000_000 + int64(startTime.Minute())*60_000_000,
				Valid:        true,
			},
			EndTime: pgtype.Time{
				Microseconds: int64(endTime.Hour())*3_600_000_000 + int64(endTime.Minute())*60_000_000,
				Valid:        true,
			},
			IsAvailable: pgtype.Bool{Bool: slot.IsAvailable, Valid: true},
		})
		if err != nil {
			return nil, fmt.Errorf("failed to set availability: %w", err)
		}

		result = append(result, &model.AvailabilitySlot{
			ID:          uuidToString(avail.ID),
			DayOfWeek:   int(avail.DayOfWeek),
			StartTime:   timeToString(avail.StartTime),
			EndTime:     timeToString(avail.EndTime),
			IsAvailable: boolVal(avail.IsAvailable),
		})
	}

	return result, nil
}

