// UploadWorkerAvatar is the resolver for the uploadWorkerAvatar field.
func (r *mutationResolver) UploadWorkerAvatar(ctx context.Context, workerID string, file graphql.Upload) (*model.WorkerProfile, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	// Get worker record
	worker, err := r.Queries.GetWorkerByID(ctx, stringToUUID(workerID))
	if err != nil {
		return nil, fmt.Errorf("worker not found: %w", err)
	}

	// Authorization: user must be the worker OR company admin OR global admin
	isOwnProfile := worker.UserID.Valid && uuidToString(worker.UserID) == claims.UserID
	isCompanyAdmin := false
	if claims.Role == "company_admin" {
		company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
		if err == nil {
			isCompanyAdmin = company.ID == worker.CompanyID
		}
	}

	if !isOwnProfile && !isCompanyAdmin && claims.Role != "global_admin" {
		return nil, fmt.Errorf("not authorized")
	}

	// Validate file type (images only)
	if !isImageFile(file.Filename) {
		return nil, fmt.Errorf("doar imagini sunt permise (jpg, png, webp)")
	}

	// Validate file size (max 10MB)
	if file.Size > 10*1024*1024 {
		return nil, fmt.Errorf("fisierul depaseste limita de 10MB")
	}

	// Build GCS path: uploads/users/{userId}/avatars (avatar belongs to user, not worker)
	path := fmt.Sprintf("uploads/users/%s/avatars", uuidToString(worker.UserID))

	// Upload to GCS with public access
	avatarURL, err := r.Storage.Upload(ctx, path, file.Filename, file.File, storage.StorageTypePublic)
	if err != nil {
		return nil, fmt.Errorf("eroare la incarcarea imaginii: %w", err)
	}

	// Update USER's avatar (not worker's) - avatar is a user-level attribute
	_, err = r.Queries.UpdateUserAvatar(ctx, db.UpdateUserAvatarParams{
		ID:        stringToUUID(uuidToString(worker.UserID)),
		AvatarUrl: stringToText(&avatarURL),
	})
	if err != nil {
		return nil, fmt.Errorf("failed to update avatar: %w", err)
	}

	// Refetch worker to return updated profile
	updated, err := r.Queries.GetWorkerByID(ctx, stringToUUID(workerID))
	if err != nil {
		return nil, fmt.Errorf("failed to refetch worker: %w", err)
	}

	return r.workerWithCompany(ctx, updated)
}

