// UploadWorkerDocument is the resolver for the uploadWorkerDocument field.
func (r *mutationResolver) UploadWorkerDocument(ctx context.Context, workerID string, documentType string, file graphql.Upload) (*model.WorkerDocument, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	// Get the worker record
	worker, err := r.Queries.GetWorkerByID(ctx, stringToUUID(workerID))
	if err != nil {
		return nil, fmt.Errorf("worker not found: %w", err)
	}

	// Authorization: Either the worker's own user OR the company admin OR global admin
	isOwnWorker := worker.UserID.Valid && uuidToString(worker.UserID) == claims.UserID

	var isCompanyAdmin bool
	if !isOwnWorker {
		// Check if user is company admin for this worker's company
		company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
		if err == nil && uuidToString(company.ID) == uuidToString(worker.CompanyID) {
			isCompanyAdmin = true
		}
	}

	if !isOwnWorker && !isCompanyAdmin && claims.Role != "global_admin" {
		return nil, fmt.Errorf("not authorized to upload documents for this worker")
	}

	path := fmt.Sprintf("uploads/workers/%s/documents", workerID)
	fileURL, err := r.Storage.Upload(ctx, path, file.Filename, file.File, storage.StorageTypePrivate)
	if err != nil {
		return nil, fmt.Errorf("failed to upload file: %w", err)
	}

	doc, err := r.Queries.CreateWorkerDocument(ctx, db.CreateWorkerDocumentParams{
		WorkerID:     stringToUUID(workerID),
		DocumentType: documentType,
		FileUrl:      fileURL,
		FileName:     file.Filename,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to save worker document: %w", err)
	}

	return dbWorkerDocToGQL(doc), nil
}

