// ReviewWorkerDocument is the resolver for the reviewWorkerDocument field.
func (r *mutationResolver) ReviewWorkerDocument(ctx context.Context, id string, approved bool, rejectionReason *string) (*model.WorkerDocument, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil || claims.Role != "global_admin" {
		return nil, fmt.Errorf("not authorized")
	}

	status := "approved"
	if !approved {
		status = "rejected"
	}

	var reason pgtype.Text
	if rejectionReason != nil {
		reason = pgtype.Text{String: *rejectionReason, Valid: true}
	}

	doc, err := r.Queries.UpdateWorkerDocumentStatus(ctx, db.UpdateWorkerDocumentStatusParams{
		ID:              stringToUUID(id),
		Status:          status,
		ReviewedBy:      stringToUUID(claims.UserID),
		RejectionReason: reason,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to review document: %w", err)
	}

	return dbWorkerDocToGQL(doc), nil
}

// ActivateWorker is the resolver for the activateWorker field.
func (r *mutationResolver) ActivateWorker(ctx context.Context, id string) (*model.WorkerProfile, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil || claims.Role != "global_admin" {
		return nil, fmt.Errorf("not authorized")
	}

	// Require personality assessment before activation.
	workerUUID := stringToUUID(id)
	has, err := r.Queries.HasPersonalityAssessment(ctx, workerUUID)
	if err != nil {
		return nil, fmt.Errorf("failed to check personality assessment: %w", err)
	}
	if !has {
		return nil, fmt.Errorf("worker must complete personality assessment before activation")
	}

	worker, err := r.Queries.ActivateWorkerStatus(ctx, workerUUID)
	if err != nil {
		return nil, fmt.Errorf("failed to activate worker: %w", err)
	}

	// Notify the worker's linked user account that they've been activated.
	if worker.UserID.Valid {
		go func(userID pgtype.UUID) {
			if _, nErr := r.Queries.CreateNotification(context.Background(), db.CreateNotificationParams{
				UserID: userID,
				Type:   db.NotificationTypeWorkerActivated,
				Title:  "Cont activat!",
				Body:   "Felicitări! Contul tău de lucrător a fost aprobat. Poți începe să primești comenzi.",
				Data:   []byte(fmt.Sprintf(`{"workerId":"%s"}`, uuidToString(worker.ID))),
			}); nErr != nil {
				log.Printf("activateWorker: failed to notify worker: %v", nErr)
			}
		}(worker.UserID)
	}

	return r.workerWithCompany(ctx, worker)
}

// UpdateWorkerServiceCategories is the resolver for the updateWorkerServiceCategories field.
func (r *mutationResolver) UpdateWorkerServiceCategories(ctx context.Context, workerID string, categoryIds []string) ([]*model.ServiceCategory, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}
	if claims.Role != "company_admin" && claims.Role != "global_admin" {
		return nil, fmt.Errorf("not authorized")
	}

	workerUUID := stringToUUID(workerID)

	// Company admin can only update workers from their own company.
	if claims.Role == "company_admin" {
		company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
		if err != nil {
			return nil, fmt.Errorf("company not found for user")
		}
		worker, err := r.Queries.GetWorkerByID(ctx, workerUUID)
		if err != nil {
			return nil, fmt.Errorf("worker not found: %w", err)
		}
		if uuidToString(worker.CompanyID) != uuidToString(company.ID) {
			return nil, fmt.Errorf("worker does not belong to your company")
		}
	}

	// Delete all existing categories and insert the new ones.
	if err := r.Queries.DeleteAllWorkerServiceCategories(ctx, workerUUID); err != nil {
		return nil, fmt.Errorf("failed to clear worker categories: %w", err)
	}
	for _, catID := range categoryIds {
		if err := r.Queries.InsertWorkerServiceCategory(ctx, db.InsertWorkerServiceCategoryParams{
			WorkerID:   workerUUID,
			CategoryID: stringToUUID(catID),
		}); err != nil {
			return nil, fmt.Errorf("failed to assign category: %w", err)
		}
	}

	// Return the updated list.
	rows, err := r.Queries.ListWorkerServiceCategories(ctx, workerUUID)
	if err != nil {
		return nil, fmt.Errorf("failed to list worker categories: %w", err)
	}
	result := make([]*model.ServiceCategory, len(rows))
	for i, row := range rows {
		result[i] = &model.ServiceCategory{
			ID:     uuidToString(row.CategoryID),
			Slug:   row.Slug,
			NameRo: row.NameRo,
			NameEn: row.NameEn,
			Icon:   textPtr(row.Icon),
		}
	}
	return result, nil
}

