// MyWorkers is the resolver for the myWorkers field.
func (r *queryResolver) MyWorkers(ctx context.Context) ([]*model.WorkerProfile, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	company, err := r.Queries.GetCompanyByAdminUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("company not found for user. please register your company first: %w", err)
	}

	workers, err := r.Queries.ListWorkersByCompany(ctx, company.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to list workers: %w", err)
	}

	// Batch-load users for all workers (1 query per unique user, not per worker).
	userMap := map[string]db.User{}
	for _, c := range workers {
		if c.UserID.Valid {
			uid := uuidToString(c.UserID)
			if _, exists := userMap[uid]; !exists {
				if u, uErr := r.Queries.GetUserByID(ctx, c.UserID); uErr == nil {
					userMap[uid] = u
				}
			}
		}
	}

	result := make([]*model.WorkerProfile, len(workers))
	for i, c := range workers {
		var uPtr *db.User
		if c.UserID.Valid {
			if u, ok := userMap[uuidToString(c.UserID)]; ok {
				uPtr = &u
			}
		}
		profile := dbWorkerToGQL(c, uPtr)
		if uPtr != nil {
			profile.User = dbUserToGQL(*uPtr)
		}
		// Compute worker stats dynamically from reviews/bookings
		r.enrichWorkerStats(ctx, c.ID, profile)
		result[i] = profile
	}

	return result, nil
}

