// MyWorkerStats is the resolver for the myWorkerStats field.
func (r *queryResolver) MyWorkerStats(ctx context.Context) (*model.WorkerStats, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	worker, err := r.Queries.GetWorkerByUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("worker profile not found: %w", err)
	}

	avgRating, err := r.Queries.GetAverageWorkerRating(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to get average rating: %w", err)
	}

	reviews, err := r.Queries.ListReviewsByWorkerID(ctx, db.ListReviewsByWorkerIDParams{
		ReviewedWorkerID: worker.ID,
		Limit:            1000,
		Offset:           0,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to list reviews: %w", err)
	}

	completedCount, err := r.Queries.CountCompletedJobsByWorker(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to count completed jobs: %w", err)
	}

	thisMonthJobs, err := r.Queries.CountThisMonthJobsByWorker(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to count this month jobs: %w", err)
	}

	thisMonthEarnings, err := r.Queries.SumThisMonthEarningsByWorker(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to sum this month earnings: %w", err)
	}

	return &model.WorkerStats{
		TotalJobsCompleted: int(completedCount),
		AverageRating:      numericToFloat(avgRating),
		TotalReviews:       len(reviews),
		ThisMonthJobs:      int(thisMonthJobs),
		ThisMonthEarnings:  numericToFloat(thisMonthEarnings),
	}, nil
}

