// SearchWorkerBookings is the resolver for the searchWorkerBookings field.
func (r *queryResolver) SearchWorkerBookings(ctx context.Context, query *string, status *string, dateFrom *string, dateTo *string, limit *int, offset *int) (*model.BookingConnection, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	worker, err := r.Queries.GetWorkerByUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("worker profile not found: %w", err)
	}

	qLimit := int32(20)
	if limit != nil {
		qLimit = int32(*limit)
	}
	qOffset := int32(0)
	if offset != nil {
		qOffset = int32(*offset)
	}

	var queryStr string
	if query != nil {
		queryStr = *query
	}
	var statusStr string
	if status != nil {
		statusStr = strings.ToLower(*status)
	}

	zeroDate := pgtype.Date{Time: time.Date(1, 1, 1, 0, 0, 0, 0, time.UTC), Valid: true}
	fromDate := zeroDate
	toDate := zeroDate
	if dateFrom != nil {
		if t, err := time.Parse("2006-01-02", *dateFrom); err == nil {
			fromDate = pgtype.Date{Time: t, Valid: true}
		}
	}
	if dateTo != nil {
		if t, err := time.Parse("2006-01-02", *dateTo); err == nil {
			toDate = pgtype.Date{Time: t, Valid: true}
		}
	}

	bookings, err := r.Queries.SearchWorkerBookings(ctx, db.SearchWorkerBookingsParams{
		WorkerID:     worker.ID,
		Limit:        qLimit + 1,
		Offset:       qOffset,
		Query:        queryStr,
		StatusFilter: statusStr,
		DateFrom:     fromDate,
		DateTo:       toDate,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to search worker bookings: %w", err)
	}

	hasNext := len(bookings) > int(qLimit)
	if hasNext {
		bookings = bookings[:qLimit]
	}

	// Batch-load clients and addresses (list only needs these two).
	clientIDs := map[string]bool{}
	addressIDs := map[string]bool{}
	for _, b := range bookings {
		clientIDs[uuidToString(b.ClientUserID)] = true
		if b.AddressID.Valid {
			addressIDs[uuidToString(b.AddressID)] = true
		}
	}
	clientMap := map[string]*model.User{}
	for cid := range clientIDs {
		if u, uErr := r.Queries.GetUserByID(ctx, stringToUUID(cid)); uErr == nil {
			clientMap[cid] = dbUserToGQL(u)
		}
	}
	addressMap := map[string]*model.Address{}
	for aid := range addressIDs {
		if a, aErr := r.Queries.GetAddressByID(ctx, stringToUUID(aid)); aErr == nil {
			addressMap[aid] = dbAddressToGQL(a)
		}
	}

	// Build service name map (single query).
	serviceNameMap := map[string]string{}
	if services, sErr := r.Queries.ListActiveServices(ctx); sErr == nil {
		for _, s := range services {
			serviceNameMap[string(s.ServiceType)] = s.NameRo
		}
	}

	edges := make([]*model.Booking, len(bookings))
	for i, b := range bookings {
		gqlBooking := dbBookingToGQL(b)
		if name, ok := serviceNameMap[string(b.ServiceType)]; ok {
			gqlBooking.ServiceName = name
		}
		if u, ok := clientMap[uuidToString(b.ClientUserID)]; ok {
			gqlBooking.Client = u
		}
		if b.AddressID.Valid {
			if a, ok := addressMap[uuidToString(b.AddressID)]; ok {
				gqlBooking.Address = a
			}
		}
		edges[i] = gqlBooking
	}

	total, _ := r.Queries.CountSearchWorkerBookings(ctx, db.CountSearchWorkerBookingsParams{
		WorkerID:     worker.ID,
		Query:        queryStr,
		StatusFilter: statusStr,
		DateFrom:     fromDate,
		DateTo:       toDate,
	})

	return &model.BookingConnection{
		Edges: edges,
		PageInfo: &model.PageInfo{
			HasNextPage: hasNext,
		},
		TotalCount: int(total),
	}, nil
}

// MyWorkerReviews is the resolver for the myWorkerReviews field.
func (r *queryResolver) MyWorkerReviews(ctx context.Context, limit *int, offset *int) (*model.ReviewConnection, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	worker, err := r.Queries.GetWorkerByUserID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("worker profile not found: %w", err)
	}

	l := int32(20)
	if limit != nil {
		l = int32(*limit)
	}
	o := int32(0)
	if offset != nil {
		o = int32(*offset)
	}

	dbReviews, err := r.Queries.ListReviewsByWorkerID(ctx, db.ListReviewsByWorkerIDParams{
		ReviewedWorkerID: worker.ID,
		Limit:            l,
		Offset:           o,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to list reviews: %w", err)
	}

	count, err := r.Queries.CountReviewsByWorkerID(ctx, worker.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to count reviews: %w", err)
	}

	reviews := make([]*model.Review, len(dbReviews))
	for i, rv := range dbReviews {
		review := dbReviewToGQL(rv)
		if booking, bErr := r.Queries.GetBookingByID(ctx, rv.BookingID); bErr == nil {
			review.Booking = dbBookingToGQL(booking)
		}
		if rv.ReviewerUserID.Valid {
			if user, uErr := r.Queries.GetUserByID(ctx, rv.ReviewerUserID); uErr == nil {
				review.Reviewer = dbUserToGQL(user)
			}
		}
		reviews[i] = review
	}

	return &model.ReviewConnection{
		Reviews:    reviews,
		TotalCount: int(count),
	}, nil
}

